final:
module full_adder (
    input  A   ,
    input  B   ,
    input  CIN ,
    output COUT,
    output SUM
);

    assign SUM = A ^ B ^ CIN;
    assign COUT = (A & B) | (A & CIN) | (B & CIN);

  always @(*) begin
    if (1'b0) begin
      COUT <= ~((A & B) | (A & CIN) | (B & CIN));
      SUM <= ~(A ^ B ^ CIN);
    end
  end

endmodule
